BEGIN TRANSACTION;
CREATE TABLE accounts (
	id INTEGER NOT NULL, 
	name VARCHAR(200) NOT NULL, 
	type VARCHAR(50) NOT NULL, 
	institution VARCHAR(200), 
	account_number_masked VARCHAR(50), 
	currency VARCHAR(10) NOT NULL, 
	color VARCHAR(20), 
	is_active BOOLEAN NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id)
);
CREATE TABLE categories (
	id INTEGER NOT NULL, 
	name VARCHAR(200) NOT NULL, 
	parent_id INTEGER, 
	color VARCHAR(20), 
	icon VARCHAR(50), 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(parent_id) REFERENCES categories (id)
);
CREATE TABLE correction_history (
	id INTEGER NOT NULL, 
	transaction_id INTEGER NOT NULL, 
	description VARCHAR(500) NOT NULL, 
	original_category_id INTEGER, 
	user_category_id INTEGER, 
	original_category_name VARCHAR(200), 
	user_category_name VARCHAR(200), 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(transaction_id) REFERENCES transactions (id), 
	FOREIGN KEY(original_category_id) REFERENCES categories (id), 
	FOREIGN KEY(user_category_id) REFERENCES categories (id)
);
CREATE TABLE import_batches (
	id INTEGER NOT NULL, 
	account_id INTEGER NOT NULL, 
	filename VARCHAR(500) NOT NULL, 
	status VARCHAR(50) NOT NULL, 
	total_rows INTEGER NOT NULL, 
	imported_rows INTEGER NOT NULL, 
	duplicate_rows INTEGER NOT NULL, 
	error_message VARCHAR(1000), 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	completed_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(account_id) REFERENCES accounts (id)
);
CREATE TABLE monthly_snapshots (
	id INTEGER NOT NULL, 
	effective_date DATE NOT NULL, 
	notes VARCHAR(1000), 
	is_confirmed BOOLEAN NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id)
);
CREATE TABLE net_worth_views (
	id INTEGER NOT NULL, 
	name VARCHAR(200) NOT NULL, 
	definition JSON NOT NULL, 
	display_order INTEGER NOT NULL, 
	is_default BOOLEAN NOT NULL, 
	is_active BOOLEAN NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id)
);
CREATE TABLE recurring_bills (
	id INTEGER NOT NULL, 
	name VARCHAR(200) NOT NULL, 
	expected_amount FLOAT, 
	due_day INTEGER, 
	category_id INTEGER, 
	tag_ids JSON NOT NULL, 
	match_keywords JSON NOT NULL, 
	is_active BOOLEAN NOT NULL, 
	is_ai_suggested BOOLEAN NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(category_id) REFERENCES categories (id)
);
CREATE TABLE schema_mappings (
	id INTEGER NOT NULL, 
	account_id INTEGER NOT NULL, 
	header_fingerprint VARCHAR(64) NOT NULL, 
	raw_headers VARCHAR(1000) NOT NULL, 
	column_mapping JSON NOT NULL, 
	date_format VARCHAR(50), 
	amount_type VARCHAR(20) NOT NULL, 
	is_confirmed BOOLEAN NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(account_id) REFERENCES accounts (id)
);
CREATE TABLE settings (
	"key" VARCHAR NOT NULL, 
	value JSON NOT NULL, 
	PRIMARY KEY ("key")
);
CREATE TABLE snapshot_items (
	id INTEGER NOT NULL, 
	snapshot_id INTEGER NOT NULL, 
	account_id INTEGER, 
	name VARCHAR(200) NOT NULL, 
	item_type VARCHAR(50) NOT NULL, 
	value FLOAT NOT NULL, 
	ticker VARCHAR(20), 
	shares FLOAT, 
	price_per_share FLOAT, 
	source VARCHAR(20) NOT NULL, 
	is_asset BOOLEAN NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(snapshot_id) REFERENCES monthly_snapshots (id), 
	FOREIGN KEY(account_id) REFERENCES accounts (id)
);
CREATE TABLE stock_holdings (
	id INTEGER NOT NULL, 
	ticker VARCHAR(20) NOT NULL, 
	name VARCHAR(200), 
	quantity FLOAT NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_stock_holdings_ticker UNIQUE (ticker)
);
CREATE TABLE stock_price_history (
	id INTEGER NOT NULL, 
	ticker VARCHAR(20) NOT NULL, 
	week_date DATE NOT NULL, 
	close_price FLOAT NOT NULL, 
	fetched_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_stock_price_week UNIQUE (ticker, week_date)
);
CREATE TABLE tags (
	id INTEGER NOT NULL, 
	name VARCHAR(100) NOT NULL, 
	type VARCHAR(50) NOT NULL, 
	color VARCHAR(20), 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (name)
);
CREATE TABLE transaction_tags (
	transaction_id INTEGER NOT NULL, 
	tag_id INTEGER NOT NULL, 
	PRIMARY KEY (transaction_id, tag_id), 
	FOREIGN KEY(transaction_id) REFERENCES transactions (id), 
	FOREIGN KEY(tag_id) REFERENCES tags (id)
);
CREATE TABLE transactions (
	id INTEGER NOT NULL, 
	account_id INTEGER NOT NULL, 
	import_batch_id INTEGER, 
	date DATE NOT NULL, 
	description VARCHAR(500) NOT NULL, 
	original_description VARCHAR(500), 
	amount FLOAT NOT NULL, 
	balance FLOAT, 
	category_id INTEGER, 
	status VARCHAR(20) NOT NULL, 
	review_status VARCHAR(20) NOT NULL, 
	confidence FLOAT, 
	ai_category_suggestion VARCHAR(200), 
	is_transfer BOOLEAN NOT NULL, 
	transfer_pair_id INTEGER, 
	raw_source JSON, 
	dedup_hash VARCHAR(64), 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(account_id) REFERENCES accounts (id), 
	FOREIGN KEY(import_batch_id) REFERENCES import_batches (id), 
	FOREIGN KEY(category_id) REFERENCES categories (id), 
	FOREIGN KEY(transfer_pair_id) REFERENCES transactions (id)
);
CREATE UNIQUE INDEX ix_monthly_snapshots_effective_date ON monthly_snapshots (effective_date);
CREATE INDEX ix_schema_mappings_header_fingerprint ON schema_mappings (header_fingerprint);
CREATE INDEX ix_snapshot_items_snapshot_id ON snapshot_items (snapshot_id);
CREATE INDEX ix_transactions_date ON transactions (date);
CREATE INDEX ix_transactions_dedup_hash ON transactions (dedup_hash);
CREATE INDEX ix_transactions_category_id ON transactions (category_id);
CREATE INDEX ix_transactions_date_account ON transactions (date, account_id);
CREATE INDEX ix_transactions_account_id ON transactions (account_id);
CREATE INDEX ix_stock_price_history_ticker ON stock_price_history (ticker);
CREATE INDEX ix_stock_price_history_week_date ON stock_price_history (week_date);
COMMIT;